SELECT rule_name
FROM automation_rules
WHERE is_active = 1;

SELECT COUNT(*) AS active_rule_count
FROM automation_rules
WHERE user_id = 1 AND is_active = 1;

SELECT access_mode
FROM user_devices
WHERE user_id = 0;

SELECT user_id, COUNT(device_id) AS device_count
FROM user_devices
GROUP BY user_id;

SELECT COUNT(device_id) AS locked_device_count
FROM device_states
WHERE state = 'LOCKED';

SELECT COUNT(*) AS device_access_count
FROM user_devices
WHERE access_frequency > 10;
